        self.food_ratings = {}
        self.cuisine_foods = {}
        for i in range(len(foods)):
            self.food_ratings[foods[i]] = ratings[i]
            if cuisines[i] not in self.cuisine_foods:
                self.cuisine_foods[cuisines[i]] = []
            self.cuisine_foods[cuisines[i]].append((foods[i], ratings[i]))

    def changeRating(self, food: str, newRating: int) -> None:
        self.food_ratings[food] = newRating

    def highestRated(self, cuisine: str) -> str:
        if cuisine not in self.cuisine_foods:
            return ""
        cuisine_foods = sorted(self.cuisine_foods[cuisine], key=lambda x: (-x[1], x[0]))
        return cuisine_foods[0][0]
